/**
 * 5e SRD Spell Definitions
 *
 * Foundational SRD spell catalog for character creation, class spell lists,
 * and rules-aware prompting. Includes a broad cross-section of core cantrips
 * and leveled spells across all nine spell levels.
 *
 * Sources: 5e SRD (CC-BY-4.0)
 */

import type { ClassName } from '../types';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type SpellSchool =
	| 'abjuration'
	| 'conjuration'
	| 'divination'
	| 'enchantment'
	| 'evocation'
	| 'illusion'
	| 'necromancy'
	| 'transmutation';

export interface SpellComponents {
	verbal?: boolean;
	somatic?: boolean;
	material?: string;
}

export interface SpellDefinition {
	name: string;
	displayName: string;
	level: number;
	school: SpellSchool;
	castingTime: string;
	range: string;
	components: SpellComponents;
	duration: string;
	concentration: boolean;
	ritual?: boolean;
	description: string;
	higherLevels?: string;
	classes: ClassName[];
	damage?: string;
	healing?: string;
	savingThrow?: 'str' | 'dex' | 'con' | 'int' | 'wis' | 'cha';
	tags?: string[];
}

