// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

export function getSpell(name: string): SpellDefinition | undefined {
	const normalized = name.trim().toLowerCase().replace(/[’']/g, '').replace(/\s+/g, '-');
	return SPELLS.find((spell) => spell.name === normalized || spell.displayName.toLowerCase().replace(/[’']/g, '') === name.trim().toLowerCase().replace(/[’']/g, ''));
}

export function getSpellsForClass(className: ClassName, maxLevel?: number): SpellDefinition[] {
	return SPELLS.filter((spell) => spell.classes.includes(className) && (maxLevel === undefined || spell.level <= maxLevel));
}

export function getCantripsForClass(className: ClassName): SpellDefinition[] {
	return getSpellsForClass(className, 0).filter((spell) => spell.level === 0);
}

export function getSpellsByLevel(level: number): SpellDefinition[] {
	return SPELLS.filter((spell) => spell.level === level);
}
